import { Booking } from '@/models/booking.dto';
import { AgentsService } from '@/services/agents/agents.service';
import { Agent } from '@/services/agents/type';
import { Component, Event, EventEmitter, Host, Prop, State, Watch, h } from '@stencil/core';
import { isAgentMode } from '../ir-booking-details/functions';

export type BillingPanels = 'agent' | 'guest';
@Component({
  tag: 'ir-billing',
  styleUrl: 'ir-billing.css',
  scoped: true,
})
export class IrBilling {
  private isAgentMode: boolean = false;
  private agentsService = new AgentsService();

  @Prop() booking: Booking;
  @Prop() agent: Agent;
  @Watch('booking')
  async handleBookingChange() {
    if (this.booking) {
      await this.resolveAgent();
      this.isAgentMode = isAgentMode(this.resolvedAgent);
    }
  }

  @State() currentTab: BillingPanels = 'agent';
  @State() resolvedAgent: Agent;

  @Event() billingClose: EventEmitter<void>;

  async componentWillLoad() {
    if (this.booking) {
      await this.resolveAgent();
      this.isAgentMode = isAgentMode(this.resolvedAgent);
    }
  }

  private async resolveAgent() {
    if (this.agent) {
      this.resolvedAgent = this.agent;
    } else if (this.booking?.agent) {
      this.resolvedAgent = await this.agentsService.getExposedAgent({ id: this.booking.agent.id });
    }
  }

  render() {
    if (this.isAgentMode) {
      return (
        <Host>
          <wa-tab-group
            activation="manual"
            onwa-tab-show={e => {
              this.currentTab = e.detail.name.toString() as BillingPanels;
            }}
            active={this.currentTab}
          >
            <wa-tab panel="guest">Guest</wa-tab>
            <wa-tab panel="agent">Agent</wa-tab>
            <wa-tab-panel name="guest">{this.currentTab === 'guest' && <ir-guest-billing booking={this.booking}></ir-guest-billing>}</wa-tab-panel>
            <wa-tab-panel name="agent">{this.currentTab === 'agent' && <ir-agent-billing booking={this.booking}></ir-agent-billing>}</wa-tab-panel>
          </wa-tab-group>
        </Host>
      );
    }
    return <ir-guest-billing booking={this.booking}></ir-guest-billing>;
  }
}
